package com.socialblog.follower.web;import org.springframework.stereotype.Component;import org.springframework.web.context.request.*;import java.util.UUID;@Component public class CorrelationIdProvider{public String current(){RequestAttributes a=RequestContextHolder.getRequestAttributes();if(a!=null){Object v=a.getAttribute(CorrelationIdFilter.ATTRIBUTE,RequestAttributes.SCOPE_REQUEST);if(v instanceof String id)return id;}return UUID.randomUUID().toString();}}
